```go
package entity

import (
	"math"
	"testing"
)

// TestUnitOrderCalculateTotalEdgeCases adds a few edge‑case scenarios that are
// not covered by the existing suite (TestUnitOrderCalculateTotal*, …).  The
// method under test has the signature:
//
//    func (o *Order) CalculateTotal()
//
// and is expected to sum `item.Price * float64(item.Quantity)` for every
// element of `o.Items`, storing the result in `o.Total`.  The test checks that
// the calculation is performed exactly as described, even when the data
// contains “odd” values such as a zero price, a zero quantity, negative
// numbers, or very large numbers that could overflow a 32‑bit int.
//
// The test is table‑driven, each sub‑test creates an `Order` with a specific
// slice of `OrderItem`s, calls `CalculateTotal()`, and then asserts the
// resulting `Total` field.
//
// NOTE: The test does **not** invoke `Validate()`.  The purpose is to verify
// the pure arithmetic performed by `CalculateTotal()` – the validation layer
// is exercised elsewhere (e.g. TestUnitOrderValidate*).
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	tests := []struct {
		name     string
		items    []OrderItem
		expected float64
	}{
		{
			name: "zero_price",
			// price is zero – contribution should be 0 regardless of quantity.
			items: []OrderItem{
				{ProductID: 1, Quantity: 5, Price: 0},
				{ProductID: 2, Quantity: 3, Price: 100},
			},
			// 0*5 + 100*3 = 300
			expected: 300,
		},
		{
			name: "zero_quantity",
			// quantity is zero – contribution should be 0 regardless of price.
			items: []OrderItem{
				{ProductID: 1, Quantity: 0, Price: 250},
				{ProductID: 2, Quantity: 4, Price: 75},
			},
			// 250*0 + 75*4 = 300
			expected: 300,
		},
		{
			name: "negative_price",
			// A negative price is not allowed by validation, but CalculateTotal
			// should still sum it mathematically.
			items: []OrderItem{
				{ProductID: 1, Quantity: 2, Price: -50},
				{ProductID: 2, Quantity: 1, Price: 200},
			},
			// (-50)*2 + 200*1 = 100
			expected: 100,
		},
		{
			name: "negative_quantity",
			// Same idea – negative quantity yields a negative contribution.
			items: []OrderItem{
				{ProductID: 1, Quantity: -3, Price: 40},
				{ProductID: 2, Quantity: 2, Price: 30},
			},
			// 40*(-3) + 30*2 = -60
			expected: -60,
		},
		{
			name: "mixed_signs",
			// Mix of positive and negative values – the net total must be exact.
			items: []OrderItem{
				{ProductID: 1, Quantity: 5, Price: 20},   // +100
				{ProductID: 2, Quantity: -2, Price: 30},  // -60
				{ProductID: 3, Quantity: 1, Price: -15},  // -15
				{ProductID: 4, Quantity: 3, Price: 0},    // 0
			},
			// 100 - 60 - 15 + 0 = 25
			expected: 25,
		},
		{
			name: "large_numbers",
			// Use values that are close to the limits of a 32‑bit int but still
			// safely representable as a float64.  The expected total is
			// calculated with 64‑bit arithmetic to avoid overflow in the test
			// itself.
			items: []OrderItem{
				{ProductID: 1, Quantity: math.MaxInt32, Price: 1.5},
				{ProductID: 2, Quantity: 2, Price: 1e9},
			},
			// (MaxInt32 * 1.5) + (2 * 1e9)
			// MaxInt32 = 2 147 483 647 → 2 147 483 647 * 1.5 = 3 221 225 470.5
			// + 2 000 000 000 = 5 221 225 470.5
			expected: 5_221_225_470.5,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			o := &Order{
				Items: tt.items,
			}
			o.CalculateTotal()

			if o.Total != tt.expected {
				t.Fatalf("unexpected total: got %v, want %v", o.Total, tt.expected)
			}
		})
	}
}
```

### Why this test does **not** duplicate existing ones
| Existing test name | What it covers | What this test adds |
|--------------------|----------------|---------------------|
| `TestUnitOrderCalculateTotal` | 3 normal items with positive price/quantity | Edge cases with zero price, zero quantity, negative values, very large numbers, mixed signs |
| `TestUnitOrderCalculateTotalEmpty` | Empty slice (`len==0`) | Zero‑price and zero‑quantity items (non‑empty slice) |
| `TestUnitOrderCalculateTotalSingleItem` | One normal item | Zero‑price, zero‑quantity, negative price/quantity, large numbers |
| `TestUnitOrderCalculateTotalLargeOrder` | 50 items, normal values | Very large *single* quantity/price that could overflow a 32‑bit int |
| `TestUnitOrderCalculateTotalFloatPrecision` | Floating‑point rounding check (0.1/0.2) | Additional floating‑point precision check with large numbers |
| `TestUnitOrderCalculateTotalSetsField` | Overwrites pre‑existing `Total` | Same logic, but combined with the edge‑case data above |

Thus the new test explores scenarios that the current suite does not hit, while still exercising the same public method (`CalculateTotal`). It lives in the same package (`entity`) and follows the project’s naming convention (`TestUnitOrderCalculateTotalEdgeCases`).

