// TestAPIOrderFullFlow проверяет полный жизненный цикл заказа через HTTP‑API.
func TestAPIOrderFullFlow(t *testing.T) {
	// 1️⃣ Запускаем полностью изолированный сервер (все репозитории, юз‑кейсы и хэндлеры).
	srv := setupTestServer(t)

	// -------------------------------------------------------------------------
	// 2️⃣ Создаём категорию, которая будет использоваться в товаре.
	//    Функция createCategory возвращает ID созданной категории.
	catID := createCategory(t, srv.URL,
		"Кофе",          // name
		"coffee",        // slug
		"Кофейные напитки", // description
	)

	// -------------------------------------------------------------------------
	// 3️⃣ Добавляем товар в только что созданную категорию.
	//    createProduct возвращает ID продукта.
	prodID := createProduct(t, srv.URL,
		"Эспрессо",   // name
		catID,        // category_id
		300,          // price (руб.)
		"Крепкий аромат", // description
		true,         // in_stock
	)

	// -------------------------------------------------------------------------
	// 4️⃣ Оформляем заказ: клиент «alice» покупает 2 шт. продукта.
	orderPayload := map[string]any{
		"customer_id": "alice",
		"items": []map[string]any{
			{
				"product_id": prodID,
				"quantity":   2,
			},
		},
	}
	resp := postJSON(t, fmt.Sprintf("%s/orders", srv.URL), orderPayload)
	defer resp.Body.Close()
	if resp.StatusCode != http.StatusCreated {
		t.Fatalf("expected status %d (Created) for order creation, got %d", http.StatusCreated, resp.StatusCode)
	}

	// В ответе получаем ID только что созданного заказа.
	var created struct {
		ID int64 `json:"id"`
	}
	decodeBody(t, resp, &created)

	// -------------------------------------------------------------------------
	// 5️⃣ Переводим заказ в статус **processing**.
	procURL := fmt.Sprintf("%s/orders/%d/process", srv.URL, created.ID)
	resp = postJSON(t, procURL, nil)
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("expected status %d (OK) for processing, got %d", http.StatusOK, resp.StatusCode)
	}
	resp.Body.Close()

	// -------------------------------------------------------------------------
	// 6️⃣ Завершаем заказ (status → completed).
	compURL := fmt.Sprintf("%s/orders/%d/complete", srv.URL, created.ID)
	resp = postJSON(t, compURL, nil)
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("expected status %d (OK) for completion, got %d", http.StatusOK, resp.StatusCode)
	}
	resp.Body.Close()

	// -------------------------------------------------------------------------
	// 7️⃣ Получаем заказ и проверяем финальные поля.
	getURL := fmt.Sprintf("%s/orders/%d", srv.URL, created.ID)
	resp = doGet(t, getURL)
