		CustomerID string  `json:"customer_id"`
		Status     string  `json:"status"`
		Total      float64 `json:"total"`
	}
	decodeBody(t, resp, &order)

	// Ожидаем статус **completed**.
	if order.Status != string(entity.OrderStatusCompleted) {
		t.Fatalf("expected order status %q, got %q", entity.OrderStatusCompleted, order.Status)
	}

	// Ожидаем правильную сумму: 2 × 300 = 600.
	expectedTotal := 2 * 300.0
	if order.Total != expectedTotal {
