```go
package entity

import (
	"math"
	"testing"
)

// TestUnitOrderCalculateTotalEdgeCases – дополнительные edge‑case‑тесты
// для метода Order.CalculateTotal().  Они не пересекаются с уже
// существующими тестами (TestUnitOrderCalculateTotal, TestUnitOrderCalculateTotalEmpty,
// TestUnitOrderCalculateTotalSingleItem, TestUnitOrderCalculateTotalLargeOrder,
// TestUnitOrderCalculateTotalFloatPrecision, TestUnitOrderCalculateTotalSetsField)
// и проверяют «крайние» варианты входных данных.
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	// helper, чтобы сравнивать float64 с учётом NaN/Inf
	equals := func(got, want float64) bool {
		switch {
		case math.IsNaN(want):
			return math.IsNaN(got)
		case math.IsInf(want, +1):
			return math.IsInf(got, +1)
		case math.IsInf(want, -1):
			return math.IsInf(got, -1)
		default:
			// обычное сравнение с небольшим допуском (1e-9)
			const eps = 1e-9
			return math.Abs(got-want) <= eps
		}
	}

	tests := []struct {
		name     string
		items    []OrderItem
		expected float64
	}{
		{
			name: "NegativePrice",
			// отрицательная цена – бизнес‑логика валидации не запрещает её,
			// CalculateTotal просто суммирует.
			items: []OrderItem{
				{ProductID: 1, Quantity: 2, Price: -10.0},
				{ProductID: 2, Quantity: 1, Price: 5.0},
			},
			// -10*2 + 5*1 = -15
			expected: -15.0,
		},
		{
			name: "ZeroPriceLargeQuantity",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1_000_000, Price: 0.0},
			},
			expected: 0.0,
		},
		{
			name: "LargeValuesOverflow",
			items: []OrderItem{
				{ProductID: 1, Quantity: 2, Price: 1e308},
			},
			// 1e308*2 = +Inf (float64 overflow)
			expected: math.Inf(+1),
		},
		{
			name: "QuantityMaxInt",
			items: []OrderItem{
				{
					ProductID: 1,
					Quantity:  int(^uint(0) >> 1), // max int for текущей архитектуры
					Price:     1.5,
				},
			},
			// При таком количестве результат тоже будет +Inf,
			// потому что 1.5 * MaxInt > MaxFloat64.
			expected: math.Inf(+1),
		},
		{
			name: "NaNPrice",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: math.NaN()},
				{ProductID: 2, Quantity: 3, Price: 10.0},
			},
			// NaN + 30 = NaN
			expected: math.NaN(),
		},
		{
			name: "InfinityPrice",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: math.Inf(+1)},
				{ProductID: 2, Quantity: 2, Price: 5.0},
			},
			// Inf + 10 = Inf
			expected: math.Inf(+1),
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			o := Order{
				Items: tt.items,
			}
			o.CalculateTotal()

			if !equals(o.Total, tt.expected) {
				t.Fatalf("unexpected total: got %v, want %v", o.Total, tt.expected)
			}
		})
	}
}
```

### Что делает тест
| Подтест | Что проверяется |
|---------|-----------------|
| **NegativePrice** | Суммирование отрицательной цены (допускается, т.к. валидация цены происходит только в `Product`, а `Order.CalculateTotal` просто считает). |
| **ZeroPriceLargeQuantity** | Корректность расчёта при нулевой цене и огромном количестве (результат должен быть `0`). |
| **LargeValuesOverflow** | Переполнение `float64` → `+Inf`. |
| **QuantityMaxInt** | Переполнение из‑за максимального `int` количества (тоже `+Inf`). |
| **NaNPrice** | Обработка `NaN`‑цен – итог должен быть `NaN`. |
| **InfinityPrice** | Обработка `+Inf`‑цен – итог должен быть `+Inf`. |

Тест использует вспомогательную функцию `equals`, которая корректно сравнивает обычные числа, `NaN` и бесконечности.  
Все новые кейсы находятся в отдельном файле, поэтому они не конфликтуют с уже существующими тестами и расширяют покрытие метода `Order.CalculateTotal()` до «крайних» сценариев.

