// 2️⃣ Добавляем товар в эту категорию.
// 3️⃣ Оформляем заказ (2 шт. товара).
// 4️⃣ Переводим заказ в статус *processing*.
// 5️⃣ Завершаем заказ (status = completed).
// На каждом шаге проверяем ответы API и итоговое состояние заказа.
func TestAPIOrderFullFlow(t *testing.T) {
	// --------------------------------------------------------------------
	// 1️⃣ Подготовка тестового сервера (чистая in‑memory SQLite БД)
	// --------------------------------------------------------------------
	srv := testhelpers.SetupTestServer(t) // httptest.Server
	client := srv.Client()
	baseURL := srv.URL

	// --------------------------------------------------------------------
	// 2️⃣ Создаём категорию (через уже существующий хелпер)
	// --------------------------------------------------------------------
	catID := testhelpers.CreateCategory(t, client, baseURL, testhelpers.Category{
		Name: "Кофе",
		Slug: "coffee",
	})

	// --------------------------------------------------------------------
	// 3️⃣ Добавляем товар в эту категорию
	// --------------------------------------------------------------------
	const productPrice = 350.0
	prodID := testhelpers.CreateProduct(t, client, baseURL, testhelpers.Product{
		CategoryID:  catID,
		Name:        "Латте",
		Description: "Ванильный латте",
		Price:       productPrice,
		ImageURL:    "https://example.com/latte.jpg",
		InStock:     true,
	})

	// --------------------------------------------------------------------
	// 4️⃣ Оформляем заказ (2 шт. товара)
	// --------------------------------------------------------------------
	orderReq := struct {
		CustomerID string `json:"customer_id"`
		Items      []struct {
			ProductID int64   `json:"product_id"`
			Quantity  int     `json:"quantity"`
			Price     float64 `json:"price,omitempty"` // цена будет игнорироваться, но поле допускается
		} `json:"items"`
	}{
		CustomerID: "alice@example.com",
		Items: []struct {
			ProductID int64   `json:"product_id"`
			Quantity  int     `json:"quantity"`
			Price     float64 `json:"price,omitempty"`
		}{
			{ProductID: prodID, Quantity: 2},
		},
	}

	resp := testhelpers.PostJSON(t, client, baseURL+"/orders", orderReq)
	if resp.StatusCode != http.StatusCreated {
		t.Fatalf("expected status %d, got %d", http.StatusCreated, resp.StatusCode)
	}
	var createdOrder entity.Order
	if err := json.NewDecoder(resp.Body).Decode(&createdOrder); err != nil {
		t.Fatalf("decode order response: %v", err)
	}
	resp.Body.Close()

	// проверяем, что CalculateTotal сработал корректно
	expectedTotal := productPrice * 2
	if createdOrder.Total != expectedTotal {
		t.Fatalf("order total mismatch: expected %.2f, got %.2f", expectedTotal, createdOrder.Total)
	}
	if createdOrder.Status != entity.OrderStatusNew {
		t.Fatalf("order status after creation must be %s, got %s", entity.OrderStatusNew, createdOrder.Status)
	}

	// --------------------------------------------------------------------
	// 5️⃣ Переводим в статус *processing*
	// --------------------------------------------------------------------
	processURL := baseURL + "/orders/" + strconv.FormatInt(createdOrder.ID, 10) + "/process"
	resp = testhelpers.PostJSON(t, client, processURL, nil)
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("process step: expected %d, got %d", http.StatusOK, resp.StatusCode)
	}
	resp.Body.Close()

	// получаем заказ ещё раз, чтобы убедиться в изменении статуса
	resp = testhelpers.Get(t, client, baseURL+"/orders/"+strconv.FormatInt(createdOrder.ID, 10))
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("GET after process: expected %d, got %d", http.StatusOK, resp.StatusCode)
	}
	var processedOrder entity.Order
	if err := json.NewDecoder(resp.Body).Decode(&processedOrder); err != nil {
		t.Fatalf("decode processed order: %v", err)
	}
	resp.Body.Close()
	if processedOrder.Status != entity.OrderStatusProcessing {
		t.Fatalf("order status after process must be %s, got %s", entity.OrderStatusProcessing, processedOrder.Status)
	}

	// --------------------------------------------------------------------
	// 6️⃣ Завершаем заказ (status → completed)
	// --------------------------------------------------------------------
	completeURL := baseURL + "/orders/" + strconv.FormatInt(createdOrder.ID, 10) + "/complete"
	resp = testhelpers.PostJSON(t, client, completeURL, nil)
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("complete step: expected %d, got %d", http.StatusOK, resp.StatusCode)
	}
	resp.Body.Close()

	// финальная проверка
	resp = testhelpers.Get(t, client, baseURL+"/orders/"+strconv.FormatInt(createdOrder.ID, 10))
	if resp.StatusCode != http.StatusOK {
		t.Fatalf("GET after complete: expected %d, got %d", http.StatusOK, resp.StatusCode)
	}
	var finalOrder entity.Order
	if err := json.NewDecoder(resp.Body).Decode(&finalOrder); err != nil {
		t.Fatalf("decode final order: %v", err)
	}
	resp.Body.Close()

	if finalOrder.Status != entity.OrderStatusCompleted {
		t.Fatalf("final status must be %s, got %s", entity.OrderStatusCompleted, finalOrder.Status)
	}
	if finalOrder.Total != expectedTotal {
		t.Fatalf("final total changed unexpectedly: expected %.2f, got %.2f", expectedTotal, finalOrder.Total)
	}
}
