### 2️⃣ Один «тест‑контейнер» — общая in‑memory DB + транзакция

```go
// file: testhelper_test.go
func withTx(t *testing.T, fn func(tx *sql.Tx)) {
    t.Helper()
    db := setupTestDB(t)               // открывает :memory: и делает миграцию
    tx, err := db.Begin()
    if err != nil { t.Fatalf("begin tx: %v", err) }
    defer func() {
        _ = tx.Rollback()               // гарантируем откат после теста
    }()
    fn(tx)
}
```

