// TestUnitOrderCalculateTotalEdgeCases – дополнительные edge‑case‑тесты
// для метода Order.CalculateTotal().  В проекте уже есть
// TestUnitOrderCalculateTotal, TestUnitOrderCalculateTotalEmpty,
// TestUnitOrderCalculateTotalSingleItem, TestUnitOrderCalculateTotalLargeOrder,
// TestUnitOrderCalculateTotalFloatPrecision и TestUnitOrderCalculateTotalSetsField.
// Здесь проверяем поведения, которые пока не покрыты:
//
// 1. Отрицательная цена (Validate() не вызывается, метод просто суммирует).
// 2. Нулевое количество – элемент не должен влиять на итог.
// 3. Очень большие значения, которые приводят к переполнению float64 → +Inf.
// 4. Смешанные нулевые и положительные цены.
// 5. Цена = NaN – итог тоже должен стать NaN (IEEE‑754 правило).
func TestUnitOrderCalculateTotalEdgeCases(t *testing.T) {
	t.Parallel()

	tests := []struct {
		name     string
		items    []OrderItem
		expected float64 // ожидаемое значение Total после вызова CalculateTotal()
	}{
		{
			name: "negative_price",
			items: []OrderItem{
				{ProductID: 1, Quantity: 2, Price: -150.0},
				{ProductID: 2, Quantity: 1, Price: 200.0},
			},
			// -150*2 + 200*1 = -100
			expected: -100.0,
		},
		{
			name: "zero_quantity",
			items: []OrderItem{
				{ProductID: 1, Quantity: 0, Price: 123.45},
				{ProductID: 2, Quantity: 5, Price: 10.0},
			},
			// 0*123.45 + 5*10 = 50
			expected: 50.0,
		},
		{
			name: "large_values_overflow",
			items: []OrderItem{
				// 1e9 * 1e200 = 1e209 → переполнение → +Inf
				{ProductID: 1, Quantity: 1_000_000_000, Price: 1e200},
			},
			expected: math.Inf(1),
		},
		{
			name: "mixed_zero_and_positive",
			items: []OrderItem{
				{ProductID: 1, Quantity: 3, Price: 0.0},
				{ProductID: 2, Quantity: 2, Price: 75.5},
				{ProductID: 3, Quantity: 1, Price: 0.0},
			},
			// 0*3 + 75.5*2 + 0*1 = 151.0
			expected: 151.0,
		},
		{
			name: "nan_price",
			items: []OrderItem{
				{ProductID: 1, Quantity: 1, Price: math.NaN()},
				{ProductID: 2, Quantity: 2, Price: 10.0},
			},
			// NaN + 20 = NaN (по правилам IEEE‑754)
			expected: math.NaN(),
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()

			o := Order{
				Items: tt.items,
			}
			o.CalculateTotal()

			if math.IsNaN(tt.expected) {
				if !math.IsNaN(o.Total) {
					t.Fatalf("expected Total to be NaN, got %v", o.Total)
				}
				return
			}

			if math.IsInf(tt.expected, 1) {
				if !math.IsInf(o.Total, 1) {
					t.Fatalf("expected Total to be +Inf, got %v", o.Total)
				}
				return
			}

			// Для обычных чисел сравниваем с небольшим допуском, чтобы
			// избавиться от мелких погрешностей floating‑point.
			const eps = 1e-9
			if diff := math.Abs(o.Total - tt.expected); diff > eps {
				t.Fatalf("Total = %v, expected %v (diff %v > %v)", o.Total, tt.expected, diff, eps)
			}
		})
	}
}
