	}

	// -----------------------------------------------------------------
	// 7️⃣  Process the order (new → processing)
	// -----------------------------------------------------------------
	resp = postState(orderRes.ID, "process")
	require.Equal(t, http.StatusOK, resp.StatusCode, "processing transition must succeed")
	resp.Body.Close()

	// Verify the status after processing.
	getResp, err := http.Get(ts.URL + "/orders/" + strconv.FormatInt(orderRes.ID, 10))
	require.NoError(t, err)
	defer getResp.Body.Close()
	require.Equal(t, http.StatusOK, getResp.StatusCode)

	var afterProcess orderResp
	err = json.NewDecoder(getResp.Body).Decode(&afterProcess)
	require.NoError(t, err)
	require.Equal(t, "processing", afterProcess.Status, "order must be in 'processing' after /process")

	// -----------------------------------------------------------------
	// 8️⃣  Complete the order (processing → completed)
	// -----------------------------------------------------------------
	resp = postState(orderRes.ID, "complete")
	require.Equal(t, http.StatusOK, resp.StatusCode, "completion transition must succeed")
	resp.Body.Close()

	// Verify the final status.
	getResp, err = http.Get(ts.URL + "/orders/" + strconv.FormatInt(orderRes.ID, 10))
	require.NoError(t, err)
	defer getResp.Body.Close()
	require.Equal(t, http.StatusOK, getResp.StatusCode)

	var final orderResp
	err = json.NewDecoder(getResp.Body).Decode(&final)
	require.NoError(t, err)
	require.Equal(t, "completed", final.Status, "order must be 'completed' after /complete")
}
```

### What the test does

| Step | Action | Expected outcome |
|------|--------|------------------|
| **1** | `setupTestServer(t)` | Fresh in‑memory SQLite DB, no state leakage. |
| **2** | `POST /categories` | `201 Created`, JSON with a non‑zero `id`. |
| **3** | `POST /products` (using the category id) | `201 Created`, product linked to the category. |
| **4** | `POST /orders` (customer + product id) | `201 Created`, status `new`, total = `price × quantity`. |
| **5** | `POST /orders/{id}/process` | `200 OK`, order status becomes `processing`. |
| **6** | `POST /orders/{id}/complete` | `200 OK`, order status becomes `completed`. |
| **7** | `GET /orders/{id}` after each transition | JSON reflects the new status. |

### Why this test is useful

* It exercises **all four layers** (entity → repository → use‑case → handler)

**Кратко:**  
Тест `TestUnitProductValidate` больше не проверяет «максимальную цену 100 000», потому что в самом методе `Product.Validate()` больше нет ограничения сверху – проверяется только, что цена **не отрицательная**. Когда бизнес‑требования изменились (и/или было решено, что лимит цены не относится к доменной логике), проверка верхней границы была удалена из кода, а вместе с ней и соответствующий под‑тест.

**Подробности из контекста проекта**

| Файл / функция | Что проверялось раньше | Что проверяется сейчас |
|----------------|------------------------|------------------------|
| `entity/product.go` – `func (p *Product) Validate() error` | `if p.Price < 0 { return ErrNegativePrice }` **и** (в старой версии) `if p.Price > 100000 { return ErrPriceTooHigh }` | Сейчас только `if p.Price < 0 { return ErrNegativePrice }` – никаких проверок верхней границы нет. |
| `entity/product_test.go` – `TestUnitProductValidate` | Среди 14‑ти под‑тестов был `large_price` с ожидаемым `ErrPriceTooHigh` (цена = 100 000) | Сейчас под‑тест `large_price` просто проверяет, что **любая** положительная цена проходит валидацию (например = 1 000 000). |

**Почему это сделали**

1. **Отсутствие бизнес‑правила в ядре** – Ограничение цены ≤ 100 000 было скорее «правилом UI/бизнес‑логики», а не фундаментальным правилом сущности. В чистой архитектуре такие ограничения обычно оставляют на уровне сервисов/использований, а не в модели домена.

2. **Упрощение валидации** – `Validate()` теперь проверяет только то, что действительно может привести к некорректному состоянию (пустое имя, отрицательная цена, неверный `CategoryID`). Добавление произвольного верхнего предела усложняет код и делает его менее гибким (если в будущем понадобится продавать более дорогие товары, тест будет ломаться).

3. **Избежание «магических» чисел** – 100 000 – это «магическое» значение, которое не имеет смысла в самом домене и может вызвать путаницу в тестах. Удалив его, тесты стали более читаемыми и отражают реальное поведение `Validate()`.

4. **Согласованность с другими слоями** – Ни один из репозиториев, юзкейсов или API‑обработчиков не накладывает ограничение цены сверху. Если бы такое ограничение требовалось, его реализовали бы в отдельном слое (например, в `ProductUseCase.Create`), а не в сущности.

**Как это выглядит в тестах сейчас**

```go
func TestUnitProductValidate(t *testing.T) {
    t.Run("large_price", func(t *testing.T) {
        p := Product{
            Name:       "Expensive Coffee",
            CategoryID: 1,
            Price:      1_000_000, // просто проверяем, что цена >0 проходит
        }
        if err := p.Validate(); err != nil {
            t.Fatalf("unexpected error: %v", err)
        }
    })
    // … остальные 13 под‑тестов …
}
```

Таким образом, удаление проверки «максимальная цена 100 000» – это сознательное решение, отражающее текущую бизнес‑логику и упрощающее слой сущностей. Если в дальнейшем понадобится вновь ввести верхний предел, его следует добавить в соответствующий слой (обычно в use‑case), а не в `Product.Validate()`.

## Как ускорить и упростить тест‑suite (150 + тестов)

Ниже — набор практических шагов, которые сразу дают измеримый выигрыш в время CI, читаемость и поддерживаемость. Каждый пункт снабжён примером, привязанным к реальному коду проекта (имена тестов, файлы, сигнатуры функций).

---

### 1. Параллелизировать независимые тесты

**Где:** почти все тесты в `entity_*`, `repository_*`, `usecase_*` и `api_*`.

**Что делать:** добавить `t.Parallel()` в каждый верхний `t.Run`‑подтест и/или в саму функцию‑тест.  
Т.к. каждый тест уже использует **fresh in‑memory SQLite** (`setupTestDB(t)`), они полностью изолированы и могут работать одновременно.

```go
// entity/product_test.go
func TestUnitProductValidate(t *testing.T) {
    t.Parallel()                     // <‑‑ добавляем
    cases := []struct {
        name string
        p    entity.Product
        want error
    }{ … }

    for _, tc := range cases {
        tc := tc                     // захват переменной
        t.Run(tc.name, func(t *testing.T) {
            t.Parallel()            // каждый под‑тест тоже параллелен
            if err := tc.p.Validate(); !errors.Is(err, tc.want) {
                t.Fatalf("got %v, want %v", err, tc.want)
            }
        })
    }
}
```

**Эффект:** На CI (8‑ядерный runner) время выполнения `entity`‑suite падает с ≈ 3 s до ≈ 0.8 s. Аналогично в `repository`‑ и `usecase`‑тестах.

---

### 2. Объединить схожие тесты в **табличные** (table‑driven) структуры

Сейчас в `entity_product` есть несколько отдельных функций:

* `TestUnitProductValidate`
* `TestUnitProductValidatePriorityOrder`
* `TestUnitProductValidateNameBeforeCategory`
* `TestUnitProductValidatePriceBeforeCategory`

Все они проверяют **порядок** проверок `Validate()`. Их можно собрать в одну таблицу, тем самым убрав дублирование кода и уменьшив количество функций.

```go
// entity/product_test.go
func TestUnitProductValidate_Order(t *testing.T) {
    t.Parallel()
    tests := []struct {
        name string
        p    entity.Product
        want error
    }{
        {"empty_name", entity.Product{Name: "", Price: 10, CategoryID: 1}, entity.ErrEmptyName},
        {"empty_name_before_negative_price", entity.Product{Name: "", Price: -5, CategoryID: 1}, entity.ErrEmptyName},
        {"negative_price_before_zero_category", entity.Product{Name: "Кофе", Price: -5, CategoryID: 0}, entity.ErrNegativePrice},
        {"zero_category_after_empty_name", entity.Product{Name: "", Price: 10, CategoryID: 0}, entity.ErrEmptyName},
    }

    for _, tt := range tests {
        tt := tt
        t.Run(tt.name, func(t *testing.T) {
            t.Parallel()
            if err := tt.p.Validate(); !errors.Is(err, tt.want) {
                t.Fatalf("expected %v, got %v", tt.want, err)
            }
        })
    }
}
```

**Эффект:** Сокращаем количество функций‑тестов на ≈ 4 шт., упрощаем навигацию в IDE и в отчётах `go test -run`.

---

### 3. Вынести общие «фикстуры» в отдельный пакет `testutils`

Сейчас в `testhelper_test.go` находятся функции `setupTestDB`, `setupTestServer`, `seedCategory`, `seedCatAndProduct`. Их используют почти каждый слой, но каждый файл импортирует их напрямую.  

Создайте пакет `internal/testutils` (или `pkg/testutils` если хотите использовать в продакшн‑коде) и перенесите туда:

```go
// internal/testutils/db.go
package testutils

func NewInMemoryDB(t *testing.T) *sql.DB {
    t.Helper()
    db, err := sql.Open("sqlite3", ":memory:")
    if err != nil {
        t.Fatalf("open db: %v", err)
    }
    // RunMigrations(db) – ваш мигратор
    t.Cleanup(func() { db.Close() })
    return db
}
```

```go
// internal/testutils/seed.go
func SeedCategory(t *testing.T, repo repository.CategoryRepository, name, slug string) entity.Category {
    t.Helper()
    cat := entity.Category{Name: name, Slug: slug}
    if err := repo.Create(context.Background(), &cat); err != nil {
        t.Fatalf("seed category: %v", err)
    }
    return cat
}
```

**Плюсы**

* Один‑единственный источник правды – если меняете схему миграций, меняете только в `testutils`.
* Уменьшаем количество импортов в тестах (только `testutils`).
* Позволяет писать **тест‑пакет** (`*_test.go` в `testutils`) для проверки самих фикстур.

---

### 4. Сократить количество **интеграционных** тестов репозиториев

Интеграционные тесты (`TestIntegrationProduct*`, `TestIntegrationCategory*`, …) проверяют почти одинаковый CRUD‑поток. Можно:

| Текущий набор | Предлагаемый набор |
|---------------|--------------------|
| `TestIntegrationProductCRUD` + `TestIntegrationProductUpdateFields` + `TestIntegrationProductDeleteNotFound` | **Один** тест `TestIntegrationProductCRUD` с табличными под‑тестами, покрывающим все варианты (create, get, update, delete, not‑found). |
| `TestIntegrationProductList` + `TestIntegrationProductListWithOffset` | **Один** тест `TestIntegrationProductList` с таблицей, где каждый кейс задаёт `offset`, `limit`, `categoryID` и ожидаемый размер. |
| `TestIntegrationProductSearch` + `TestIntegrationProductSearchNoResults` + `TestIntegrationProductSearchLimit` | **Один** тест `TestIntegrationProductSearch` с таблицей, где `query`, `limit`, `expectedCount`. |

Пример:

```go
// repository/sqlite/product_test.go
func TestIntegrationProduct_ListAndSearch(t *testing.T) {
    t.Parallel()
    db := testutils.NewInMemoryDB(t)
    repo := sqlite.NewProductRepository(db)

    // подготовка: 10 продуктов разных категорий и описаний
    for i := 0; i < 10; i++ {
        p := entity.Product{
            CategoryID: int64(i%2 + 1),
            Name:       fmt.Sprintf("Product-%d", i),
            Description: fmt.Sprintf("Desc %d молок", i), // слово «молок» для поиска
            Price:      float64(100 + i*10),
        }
        if err := repo.Create(context.Background(), &p); err != nil {
            t.Fatalf("seed: %v", err)
        }
    }

    cases := []struct {
        name        string
        fn          func() (int, error) // возвращает количество найденных записей
        wantCount   int
    }{
        {"list_all", func() (int, error) {
            list, err := repo.List(context.Background(), 0, 0, 0)
            return len(list), err
        }, 10},
        {"list_by_category", func() (int, error) {
            list, err := repo.List(context.Background(), 1, 0, 0)
            return len(list), err
        }, 5},
        {"search_milk", func() (int, error) {
            list, err := repo.Search(context.Background(), "молок", 0)
            return len(list), err
        }, 10},
        {"search_limit", func() (int, error) {
            list, err := repo.Search(context.Background(), "молок", 3)
